+/// Sample variance with Bessel correction.
+#[must_use]
+#[allow(clippy::cast_precision_loss)]
+fn sample_variance(values: &[f64]) -> Option<f64> {
+    let n = values.len();
+    if n < 2 {
+        return None;
+    }
+    let mean = values.iter().sum::<f64>() / n as f64;
+    let sum_sq: f64 = values.iter().map(|v| (v - mean).powi(2)).sum();
